output.format:
{
  "status": "success|warning|error",
  "status_criteria": {
    "success": "関連するマッチを発見、確信度が高い",
    "warning": "部分的なマッチ、または確信度が中程度",
    "error": "マッチなし、または確信度が低い"
  },
  "confidence": "高|中|低（根拠の強さと残る不明点を添えて）",
  "summary": "検索サマリー",
  "metrics": {"files_searched": 0, "matches_found": 0},
  "results": [{"file": "path", "line": 0, "context": "..."}],
  "next_actions": ["..."]
}

